6	/**
7	 * Represents the decision outcome for sending a game invitation.
8	 *
9	 * @interface InvitationDecision
10	 * @property {('ready' | 'skipped')} status - The current status of the
11	 * invitation decision.
12	 * @property {('ready' | 'no-upcoming-game' | 'already-sent' | 'too-early')}
13	 * reason - The reason for the current status.
14	 * @property {number} [gameDayId] - Optional identifier for the game day.
15	 * @property {Date} [gameDate] - Optional date when the game is scheduled.
16	 * @property {Date} [mailDate] - Optional date when the invitation email should
17	 * be sent.
18	 * @property {boolean} overrideTimeCheck - Flag indicating whether to bypass
19	 * time-based sending restrictions.
20	 * @property {(string | null)} [customMessage] - Optional custom message to
21	 * include in the invitation.
22	 */
23	export interface InvitationDecision {
24	    status: 'ready' | 'skipped';
25	    reason: 'ready' | 'no-upcoming-game' | 'already-sent' | 'too-early';
26	    gameDayId?: number;
27	    gameDate?: Date;
28	    mailDate?: Date;
29	}
30	
31	/**
32	 * Calculates the mail date for a game invitation, which is set to 9:00 AM on
33	 * the previous working day (excluding weekends and UK bank holidays).
34	 *
35	 * @param gameDate - The date of the game for which to calculate the mail date
36	 * @returns A Date object set to 9:00 AM on the last working day before the game
37	 * date
38	 *
39	 * @remarks
40	 * The function will keep moving backwards one day at a time until it finds a
41	 * working day. A working day is determined by the `isWorkingDay` helper
42	 * function, which excludes both weekends and UK bank holidays.
43	 */
44	const getMailDate = async (gameDate: Date): Promise<Date> => {
45	    const bankHolidays = await getBankHolidays();
46	    const mailDate = new Date(gameDate);
47	    mailDate.setHours(9, 0, 0, 0);
48	    mailDate.setDate(mailDate.getDate() - 1);
49	
50	    while (!isWorkingDay(mailDate, bankHolidays)) {
51	        mailDate.setDate(mailDate.getDate() - 1);
52	    }
53	
54	    return mailDate;
55	};
56	
57	/**
58	 * Determines whether an invitation email should be sent for an upcoming game.
59	 *
60	 * This function checks if there is an upcoming game, whether an invitation has
61	 * already been sent, and whether the current time has reached the scheduled
62	 * mail date (unless overridden).
63	 *
64	 * When `override` is true the function short-circuits before fetching the
65	 * bank-holiday data, so it avoids any outbound network request.
66	 *
67	 * @param options - Configuration options for the invitation decision
68	 * @param options.overrideTimeCheck - If true, bypasses all timing checks and
69	 * returns ready immediately (without computing the mail date).
70	 * @param options.customMessage - Optional custom message to include with the
71	 * invitation
72	 *
73	 * @returns A promise that resolves to an InvitationDecision object containing:
74	 * - `status`: Either 'ready' (should send) or 'skipped' (should not send)
75	 * - `reason`: The reason for the decision ('no-upcoming-game', 'already-sent',
76	 *   'too-early', or 'ready')
77	 * - `gameDayId`: The ID of the game day (if applicable)
78	 * - `gameDate`: The date of the game (if applicable)
79	 * - `mailDate`: The calculated mail send date (only set when override is false)
80	 *
81	 * @example
82	 * ```typescript
83	 * const decision = await getInvitationDecision({ overrideTimeCheck: false });
84	 * if (decision.status === 'ready') {
85	 *   // Send invitation email
86	 * }
87	 * ```
88	 */
89	export async function getInvitationDecision(override = false): Promise<InvitationDecision> {
90	    const upcomingGame = await gameDayService.getUpcoming();
91	
92	    if (!upcomingGame) {
93	        return {
94	            status: 'skipped',
95	            reason: 'no-upcoming-game',
96	        };
97	    }
98	
99	    if (upcomingGame.mailSent && !override) {
100	        return {
101	            status: 'skipped',
102	            reason: 'already-sent',
103	            gameDayId: upcomingGame.id,
104	            gameDate: upcomingGame.date,
105	        };
106	    }
107	
108	    // Skip the external bank-holidays fetch when the caller has already said
109	    // "send regardless of timing" — the mail date is irrelevant in that case.
110	    if (override) {
111	        return {
112	            status: 'ready',
113	            reason: 'ready',
114	            gameDayId: upcomingGame.id,
115	            gameDate: upcomingGame.date,
116	        };
117	    }
118	
119	    const mailDate = await getMailDate(upcomingGame.date);
120	    const shouldSend = new Date() >= mailDate;
121	
122	    return {
123	        status: shouldSend ? 'ready' : 'skipped',
124	        reason: shouldSend ? 'ready' : 'too-early',
125	        gameDayId: upcomingGame.id,
126	        gameDate: upcomingGame.date,
127	        mailDate,
128	    };
129	}
